import * as React from 'react';
import PropTypes from 'prop-types';
import LinearProgress from '@mui/material/LinearProgress';
import Typography from '@mui/material/Typography';
import Box from '@mui/material/Box';

function LinearProgressWithLabel(props) {
    const { value } = props;
  return (
    <Box sx={{ display: 'flex', alignItems: 'center' }}>
      <Box sx={{ width: '100%', mr: 1 }}>
        <LinearProgress variant="determinate" {...props} sx={{ height:'1.3vh'}} color='skills'/>
      </Box>
      <Box sx={{ minWidth: 35 }}>
        <Typography variant="body2" color="text.secondary" sx={{ fontSize:'20px'}}>{`${Math.round(
          value,
        )}`}</Typography>
      </Box>
    </Box>
  );
}

LinearProgressWithLabel.propTypes = {
  /**
   * The value of the progress indicator for the determinate and buffer variants.
   * Value between 0 and 100.
   */
  value: PropTypes.number.isRequired,
};

export default function ProgressBar(props) {
    const { skill, sup } = props;
    const [progress, setProgress] = React.useState(10);

    React.useEffect(() => {
        const timer = setInterval(() => {
            if(progress < sup) {
                setProgress((prevProgress) => (prevProgress >= sup ? prevProgress : prevProgress + 10));
            }
        }, 50);
        return () => {
            clearInterval(timer);
        };
    }, [progress]);

    return (
      <Box>
        <Typography color='text.main'>{skill}</Typography>
        <LinearProgressWithLabel value={progress} />
      </Box>
    );
}
