import * as React from 'react';
import Container from '@mui/material/Container';
import CustomTypograhy from '../atoms/CustomTypography';

export default function AboutDetail() {
    return(
        <Container sx={{ mt:'1%' }}>
            <Container>
                <CustomTypograhy variant='h4' typography='Detail' />
            </Container>
            <Container sx={{ pt:'1%'}}> 
                <CustomTypograhy variant='body' typography='
                福岡出身、東京在住のエンジニア。趣味は読書やドライブとか。
                メインはバックエンド開発。フロントはアマチュア。インフラも手を付け始める。
                ' />
                <CustomTypograhy variant='body' typography='
                大学時代に、Web開発や業務用OCRの開発などの業務を経験。また人材系サービスを提供するベンチャー企業で、採用コンサルティングの支援などに取り組む。
                現在はIT/通信系の会社で、セキュリティに関する企画/開発やFintech系の開発業務に取り組む。
                ' />
            </Container>
        </Container>
    );
};