import * as React from 'react';
import SpeedDial from '@mui/material/SpeedDial';
import SpeedDialAction from '@mui/material/SpeedDialAction';
import LinkIcon from '@mui/icons-material/Link';
import GitHubIcon from '@mui/icons-material/GitHub';
import FacebookIcon from '@mui/icons-material/Facebook';
import InstagramIcon from '@mui/icons-material/Instagram';
import { Box } from '@mui/material';
import Button from '@mui/material/Button';

const actions = [
  { icon: <GitHubIcon onClick={() => window.open("https://github.com/Kdy0115",'_blank')}/>, name: 'GitHub' },
  { icon: <FacebookIcon onClick={() => window.open("https://www.facebook.com/profile.php?id=100023313707559",'_blank')} />, name: 'Facebook' },
  { icon: <InstagramIcon onClick={() => window.open("https://www.instagram.com/kdddyyyyy",'_blank')}/>, name: 'Instagram' },
];

export default function ShareLink() {
  const [open, setOpen] = React.useState(false);
  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);

  return (
      <SpeedDial
        ariaLabel="SpeedDial controlled open example"
        direction='up'
        icon={<LinkIcon />}
        sx={{ position:'fixed', bottom:30, left:30 }}
        onClose={handleClose}
        onOpen={handleOpen}
        open={open}
      >
        {actions.map((action) => (
          <SpeedDialAction
            key={action.name}
            icon={action.icon}
            tooltipTitle={action.name}
            onClick={handleClose}
          />
        ))}
      </SpeedDial>
  );
}
