import * as React from 'react';
import Button from '@mui/material/Button';
import CustomTypograhy from '../atoms/CustomTypography';
import Backdrop from '@mui/material/Backdrop';
import Box from '@mui/material/Box';
import Modal from '@mui/material/Modal';
import Fade from '@mui/material/Fade';
import Dialog from '@mui/material/Dialog';
import DialogContent from '@mui/material/DialogContent';
import DialogContentText from '@mui/material/DialogContentText';
import AboutCarrerModal from '../atoms/AboutCareerModal';
import Typography from '@mui/material/Typography';
import Fab from '@mui/material/Fab';
import ChevronLeftIcon from '@mui/icons-material/ChevronLeft';
import ClearIcon from '@mui/icons-material/Clear';
import { ThemeProvider } from '@mui/material/styles';

export default function CareerButton(props) {
    const buttonText = props.buttonText;

    const [open, setOpen] = React.useState(false);
    const [scroll, setScroll] = React.useState('paper');

    const handleClickOpen = (scrollType) => () => {
        setOpen(true);
        setScroll(scrollType);
    };

    const handleClose = () => {
        setOpen(false);
    };

    const descriptionElementRef = React.useRef(null);
    React.useEffect(() => {
        if (open) {
            const { current: descriptionElement } = descriptionElementRef;
            if (descriptionElement !== null) {
                descriptionElement.focus();
            }
        }
    }, [open]);

      return (
        <React.Fragment>
            <Button variant="contained" size='large' onClick={handleClickOpen('paper')} color='about'>
                <Typography color='text.reverse' >{ buttonText }</Typography>
            </Button>
            <Dialog
                open={open}
                onClose={handleClose}
                scroll={scroll}
                aria-labelledby="scroll-dialog-title"
                aria-describedby="scroll-dialog-description"
                fullScreen='true'
            >
                {/* <DialogTitle id="scroll-dialog-title">Subscribe</DialogTitle> */}
                <DialogContent dividers={scroll === 'body'}>
                <DialogContentText
                    id="scroll-dialog-description"
                    ref={descriptionElementRef}
                    tabIndex={-1}
                >
                <AboutCarrerModal year="2016年4月-2020年3月" content="九州工業大学 情報工学部 知能情報工学科" detail="情報科学やアルゴリズム、機械学習などの専門を学ぶ"/>                                     
                <AboutCarrerModal 
                  year="2018年9月-2021年3月" 
                  content="株式会社パイプドビッツ" 
                  detail="Webシステムの開発や開発業務のサポート、テスト等を経験。新規事業企画などにも取り組む。
                  "/>                      
                <AboutCarrerModal 
                  year="2019年11月-2021年9月" 
                  content="株式会社POL" 
                  detail="業務効率化ツールの開発、データ分析、インターンシップ企画、オペレーション効率化などを経験。
                  "/>     
                <AboutCarrerModal 
                  year="2021年4月-2022年3月" 
                  content="SBイノベンチャー株式会社" 
                  detail="マッチングアプリの開発にてフロントからバックエンド、要件定義や設計を経験。
                  "/>                            
                <AboutCarrerModal 
                  year="2021年11月-2022年3月" 
                  content="株式会社Info Deliver" 
                  detail="OCRや文字認識AI開発のサポート、研究開発
                  "/>                
                <AboutCarrerModal 
                  year="2020年4月-2022年3月" 
                  content="九州工業大学院 情報工学府 情報創成工学専攻研究科　修了" 
                  detail="空調制御最適化のためのエージェントシミュレーション開発。電機メーカーとの共同研究を行う。
                  ソフトウェア工学やプロジェクトマネジメント、アジャイル開発、クラウドコンピューティングを専門に学ぶ。
                  "/>
                <AboutCarrerModal 
                  year="2022年4月～現在" 
                  content="ソフトバンク株式会社" 
                  detail="システムエンジニアとして新卒入社
                  サイバーセキュリティ部にてセキュリティ企画/開発と国際間キャリア決済システムの開発を兼務。
                  "/>                                                                  
                </DialogContentText>
                </DialogContent>
                <Fab color='primary' aria-label="add" sx={{ position: 'absolute', top:10, right:30, height:'3vh', width:'5vh'}} onClick={handleClose}>
                    <ClearIcon />
                </Fab>
            </Dialog>
        </React.Fragment>
      );    
    };  