import * as React from 'react';
import Container from '@mui/material/Container';
import CustomTypograhy from '../atoms/CustomTypography';
import Image from '../atoms/Image';
import ProfileItem from '../molecules/ProfileItem';
import Grid from '@mui/material/Grid';
import Box from '@mui/material/Box';
import AboutButtons from './AboutButtons';

export default function AboutMain() {
    return(
        <Container>
            <Grid container spacing={1}>
                <Grid item xs={5}>
                    <Image />
                </Grid>
                <Grid item xs={7}>
                    <Box color='text.main'>
                        <ProfileItem title="Name" value="村上 嵩大 (Murakami Kodai)" />
                        <ProfileItem title="Birthday" value="1996/01/31" mt='3%' />
                        <ProfileItem title="Education" value="M.S. in Computer Science" mt='3%' />
                        <ProfileItem title="Occupation" value="Software Developer" mt='3%' mb='3%' />
                    </Box>
                    <AboutButtons />
                </Grid>
            </Grid>
        </Container>
    );
};