import React, { useState } from 'react';
import FormControl from '@mui/material/FormControl';
import TextField from '@mui/material/TextField';
import Container from '@mui/material/Container';
import Grid from '@mui/material/Grid';
import LoadingButton from '@mui/lab/LoadingButton';
import SendIcon from '@mui/icons-material/Send';
import Typography from '@mui/material/Typography';
import { init, send } from 'emailjs-com';
import Alert from '@mui/material/Alert';
import Collapse from '@mui/material/Collapse';

export default function ContactForm() {
  const [mail, setMail] = useState('');
  const [name, setName] = useState('');
  const [comment, setComment] = useState('');

  // const { senderMail, senderName, senderComment } = props;
  const [ loading, setLoading ] = useState(false);
  const [ elLoading, setElLoading ] = useState(false);
  const [ submitText, setSubmitText] = useState('Send');
  const [ alert, setAlert ] = useState({
    open: false,
    alertType: '',
    alertMessage: '',
  });

  const sendMail = () => {
    const userID = "4cnDOmionBiT01_t2";
    const serviceID = "portfolio_mail";
    const templateID = "template_3ofd47s";
    if (userID !== undefined && serviceID !== undefined && templateID !== undefined) {
      init(userID);
  
      const template_param = {
          from_name: name,
          from_mail: mail,
          message: comment
      };

      const disableSend = mail === '' || name === '' || comment === '';
      if (disableSend == false){
        setSubmitText('');
        setLoading(true)
        send(serviceID, templateID, template_param).then(() => {
          setLoading(false)
          setSubmitText('SEND');
          setElLoading(true)
          setAlert({...alert, open: true, alertType: 'success', alertMessage: 'Successfully sending your mail!'})
          
          setTimeout(() => {
            setAlert({...alert, open: false, alertType: '', alertMessage: ''})
            setElLoading(false)
          }, 3000);
        });
      } else{
        setElLoading(true)
        setAlert({...alert, open: true, alertType: 'error', alertMessage: 'Error sending your mail!'})
        // clearInput();
        setTimeout(() => {
          setAlert({...alert, open: false, alertType: '', alertMessage: ''})
          setElLoading(false)
        }, 3000);
      }
    }
  };
  const handleClick = (e) => {
    e.preventDefault();
    sendMail();
  };


    return (
        <Container>
          <Grid container direction="column" alignItems="center">
            <FormControl>
              <Grid item>
                <TextField color='contactInput' sx={{ mt:'3%', width:'600px'}} label="Your Mail" variant="outlined" value={mail} onChange={(e) => setMail(e.target.value)} required/>
              </Grid>
              <Grid item>
                <TextField color='contactInput' sx={{ mt:'3%', width:'600px'}} id="outlined-basic user-name" label="Name" variant="outlined" value={name} onChange={(e) => setName(e.target.value)} required/>
              </Grid>
              <Grid item>
                <TextField color='contactInput' sx={{ mt:'3%', width:'600px'}} id="outlined-multiline-flexible contact-input" label="Comment" multiline maxRows={4} value={comment} onChange={(e) => setComment(e.target.value)} required/>
              </Grid>
              <Grid item>
                <LoadingButton color='contact' sx={{ mt:'3%', ml:'40%' }} disabled={elLoading} loading={loading} variant="contained" endIcon={<SendIcon color='text.main' />} size="large" onClick={handleClick}>
                  <Typography color='text.main'>{submitText}</Typography>
                </LoadingButton>
              </Grid>
              <Grid item>
                <Collapse in={alert.open}>
                  <Alert sx={{ mt:'3%' }} severity={alert.alertType}>{alert.alertMessage}</Alert>
                </Collapse>
                {/* </Stack> */}
              </Grid>

            </FormControl>
          </Grid>
        </Container>
    );
  }