import * as React from 'react';
import CustomTypograhy from '../atoms/CustomTypography';
import Grid from '@mui/material/Grid';
import Box from '@mui/material/Box';
import { Container } from '@mui/system';

ProfileItem.defaultProps = {
    variant: 'body1',
    align: 'inherit',
    typography: 'Input text!',
    pt: '0px',
    pr: '0px',
    pb: '0px',
    pl: '0px',
    mt: '0px',
    mr: '0px',
    mb: '0px',
    ml: '0px'
  };

export default function ProfileItem(props) {
    const title = props.title;
    const value = props.value;

    const pt = props.pt;
    const pr = props.pr;
    const pb = props.pb;
    const pl = props.pl;

    const mt = props.mt;
    const mr = props.mr;
    const mb = props.mb;
    const ml = props.ml;   

    return(
    <Container sx={{ pt:pt, pr:pr, pb:pb, pl:pl, mt:mt, mr:mr, mb:mb, ml:ml }}>
        <Grid container spacing={1}>
            <Grid item xs={4}>
                <Box>
                    <CustomTypograhy variant='h5' typography={ title } />
                </Box>
            </Grid>
            <Grid item xs={8}>
                <Box>
                    <CustomTypograhy variant='h5' typography={ value } />
                </Box>
            </Grid>
        </Grid>
    </Container>
    );
};