import * as React from 'react';
import Container from '@mui/material/Container';
import { CssBaseline } from '@mui/material';
import PageHeadTitle from '../modules/PageHeadTitle';
import AboutDetail from '../modules/AboutDetail';
import AboutMain from '../modules/AboutMain';
import FadeIn from 'react-fade-in/lib/FadeIn';
import { useInView } from 'react-intersection-observer';

export default function PageAbout() {
  const { ref, inView } = useInView({
    // オプション
    rootMargin: '-150px', // ref要素が現れてから50px過ぎたら
    triggerOnce: true, // 最初の一度だけ実行
  });

    return (
      <React.Fragment>
        <CssBaseline />
          <Container  maxWidth="xl" sx={{ height:'100vh' }} ref={ ref }>
              <PageHeadTitle typography='About' color='about.main' />
              {inView && (
                <FadeIn transitionDuration="1600">
                  <AboutMain />
                  <AboutDetail />
                </FadeIn>
              )}
          </Container>
      </React.Fragment>
    );
  };