import Container from "@mui/material/Container";
import CareerButton from "../molecules/CareerButton";
import Grid from "@mui/material/Grid";
import CertificationButton from '../molecules/CertificationButton';

export default function AboutButtons() {
    return (
        <Container>
            <Grid container spacing={1}>
                <Grid item xs={6}>
                    <CareerButton buttonText='Career' />
                </Grid>
                <Grid item xs={6}>
                    <CertificationButton buttonText='Comming Soon' />
                </Grid>
            </Grid>
        </Container>
    );
};